import React from 'react';
import { View, StyleSheet, Image } from 'react-native';
import Swiper from 'react-native-swiper';

const Banner = () => {
  const images = [
    { id: 1, source: require('../../assets/images/slider.jpg') },
    { id: 2, source: require('../../assets/images/slider1.jpg') },
    { id: 3, source: require('../../assets/images/slider3.jpg') },
  ];

  const renderImages = () => {
    return images.map((image) => (
      <View style={styles.slide} key={image.id}>
        <Image source={image.source} style={styles.image} resizeMode="cover" />
      </View>
    ));
  };

  return (
    <View style={styles.container}>
      <Swiper
        autoplay
        autoplayTimeout={5}
        showsPagination={false}
        style={styles.wrapper}
      >
        {renderImages()}
      </Swiper>
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    height: 200,
    alignItems: 'center',
  },
  wrapper: {},
  slide: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
  },
  image: {
    width: '100%',
    height: '100%',
  },
});

export default Banner;
